-- Session 3C: additive confirmed on-hand rows for procurement AI evidence RPC.
-- in_stock_rows comes from inventory_balances (qty > 0), not procurement lifecycle alone.

create or replace function public.get_procurement_ai_operational_evidence(
  p_project_id uuid,
  p_limit integer default 40,
  p_offset integer default 0
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_limit integer := least(greatest(coalesce(p_limit, 40), 1), 80);
  v_offset integer := greatest(coalesce(p_offset, 0), 0);
  v_ai text;
  v_finance text;
  v_ordered_lines jsonb := '[]'::jsonb;
  v_procurement_items jsonb := '[]'::jsonb;
  v_in_stock_rows jsonb := '[]'::jsonb;
begin
  if v_uid is null then
    return jsonb_build_object(
      'effective_finance_visibility', null,
      'ordered_lines', '[]'::jsonb,
      'procurement_items', '[]'::jsonb,
      'in_stock_rows', '[]'::jsonb
    );
  end if;

  if not public.can_access_project(p_project_id) then
    return jsonb_build_object(
      'effective_finance_visibility', null,
      'ordered_lines', '[]'::jsonb,
      'procurement_items', '[]'::jsonb,
      'in_stock_rows', '[]'::jsonb
    );
  end if;

  v_ai := public.effective_ai_access_for_profile(p_project_id);
  if v_ai is null or v_ai = 'none' then
    return jsonb_build_object(
      'effective_finance_visibility', null,
      'ordered_lines', '[]'::jsonb,
      'procurement_items', '[]'::jsonb,
      'in_stock_rows', '[]'::jsonb
    );
  end if;

  v_finance := coalesce(public.effective_finance_visibility(p_project_id), 'none');

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'order_line_id', rows.order_line_id,
        'order_id', rows.order_id,
        'order_status', rows.order_status,
        'ordered_at', rows.ordered_at,
        'delivery_due_at', rows.delivery_due_at,
        'procurement_item_id', rows.procurement_item_id,
        'procurement_item_title', rows.procurement_item_title,
        'estimate_resource_line_id', rows.estimate_resource_line_id,
        'estimate_resource_line_resource_type', rows.estimate_resource_line_resource_type,
        'title', rows.title,
        'quantity', rows.quantity,
        'unit', rows.unit,
        'created_at', rows.created_at
      )
      order by rows.sort_order_ts desc, rows.created_at desc, rows.order_line_id
    ),
    '[]'::jsonb
  )
  into v_ordered_lines
  from (
    select
      ol.id as order_line_id,
      o.id as order_id,
      o.status as order_status,
      o.ordered_at,
      o.delivery_due_at,
      ol.procurement_item_id,
      pi.title as procurement_item_title,
      pi.estimate_resource_line_id,
      erl.resource_type as estimate_resource_line_resource_type,
      ol.title,
      ol.quantity,
      ol.unit,
      ol.created_at,
      coalesce(o.ordered_at, o.created_at) as sort_order_ts
    from public.order_lines ol
    join public.orders o
      on o.id = ol.order_id
    left join public.procurement_items pi
      on pi.id = ol.procurement_item_id
    left join public.estimate_resource_lines erl
      on erl.id = pi.estimate_resource_line_id
    where o.project_id = p_project_id
    order by coalesce(o.ordered_at, o.created_at) desc, ol.created_at desc, ol.id
    offset v_offset
    limit v_limit
  ) rows;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'procurement_item_id', rows.procurement_item_id,
        'estimate_resource_line_id', rows.estimate_resource_line_id,
        'estimate_resource_line_resource_type', rows.estimate_resource_line_resource_type,
        'task_id', rows.task_id,
        'title', rows.title,
        'category', rows.category,
        'quantity', rows.quantity,
        'unit', rows.unit,
        'status', rows.status,
        'created_at', rows.created_at,
        'updated_at', rows.updated_at
      )
      order by rows.updated_at desc, rows.procurement_item_id
    ),
    '[]'::jsonb
  )
  into v_procurement_items
  from (
    select
      pi.id as procurement_item_id,
      pi.estimate_resource_line_id,
      erl.resource_type as estimate_resource_line_resource_type,
      pi.task_id,
      pi.title,
      pi.category,
      pi.quantity,
      pi.unit,
      pi.status,
      pi.created_at,
      pi.updated_at
    from public.procurement_items pi
    left join public.estimate_resource_lines erl
      on erl.id = pi.estimate_resource_line_id
    where pi.project_id = p_project_id
      and pi.status <> 'cancelled'
    order by pi.updated_at desc, pi.id
    offset v_offset
    limit v_limit
  ) rows;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'inventory_item_title', rows.inventory_item_title,
        'inventory_item_spec', rows.inventory_item_spec,
        'unit', rows.unit,
        'quantity', rows.quantity,
        'location_title', rows.location_title,
        'last_received_at', rows.last_received_at
      )
      order by rows.sort_ts desc, rows.inventory_item_id
    ),
    '[]'::jsonb
  )
  into v_in_stock_rows
  from (
    select
      ii.title as inventory_item_title,
      nullif(
        trim(both from coalesce(ii.notes, ii.sku, '')),
        ''
      ) as inventory_item_spec,
      ii.unit,
      ib.quantity,
      coalesce(il.title, 'Unassigned') as location_title,
      (
        select max(im.created_at)
        from public.inventory_movements im
        where im.project_id = p_project_id
          and im.inventory_item_id = ib.inventory_item_id
          and im.inventory_location_id is not distinct from ib.inventory_location_id
          and im.movement_type = 'receipt'
          and im.delta_qty > 0
      ) as last_received_at,
      ib.updated_at as sort_ts,
      ib.inventory_item_id
    from public.inventory_balances ib
    join public.inventory_items ii
      on ii.id = ib.inventory_item_id
      and ii.project_id = ib.project_id
    left join public.inventory_locations il
      on il.id = ib.inventory_location_id
      and il.project_id = ib.project_id
    where ib.project_id = p_project_id
      and ib.quantity > 0
    order by ib.updated_at desc, ib.inventory_item_id
    offset v_offset
    limit v_limit
  ) rows;

  return jsonb_build_object(
    'effective_finance_visibility', v_finance,
    'ordered_lines', v_ordered_lines,
    'procurement_items', v_procurement_items,
    'in_stock_rows', v_in_stock_rows
  );
end;
$$;

revoke all on function public.get_procurement_ai_operational_evidence(uuid, integer, integer) from public;
grant execute on function public.get_procurement_ai_operational_evidence(uuid, integer, integer) to authenticated;
